const _ = require('lodash');
const problemsData = require('../../data/problems.json');

class ProblemsService {
  /**
   * List problems with optional filters and include component language/status totals
   * @param {Object} params
   * @param {boolean} params.includeComponents - whether to include component language/status totals
   * @param {number} params.limit - max number of problems to return
   * @param {string[]} [params.tags] - filter problems by tags
   * @param {string[]} [params.difficulties] - filter problems by difficulty
   * @returns {Object} result with problems and metadata
   */
  static listProblems({ includeComponents = false, limit = 50, tags = [], difficulties = [] }) {
    // Filter problems by tags and difficulties
    let filtered = problemsData.filter(problem => {
      if (tags.length > 0 && !tags.every(t => problem.tags.includes(t))) return false;
      if (difficulties.length > 0 && !difficulties.includes(problem.difficulty)) return false;
      return true;
    });

    // Limit the filtered problems
    const limited = filtered.slice(0, limit);

    // Prepare metadata
    const metadata = {};

    if (includeComponents) {
      // Calculate componentLanguageTotals and componentStatusTotals for the limited set
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      limited.forEach(problem => {
        if (problem.components) {
          problem.components.forEach(component => {
            // Language totals
            if (component.language) {
              componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
            }
            // Status totals
            if (component.status) {
              componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
            }
          });
        }
      });

      metadata.componentLanguageTotals = componentLanguageTotals;
      metadata.componentStatusTotals = componentStatusTotals;
    }

    return {
      problems: limited,
      metadata,
    };
  }
}

module.exports = ProblemsService;
